record.action_create_order_and_update_measurements(data)

for appt in records:
    appt.write({'start_sync_to_i360': False})
    for order in appt.sale_order_ids:
        order.write({ 'is_data_upload_completed': True})

record.action_generate_contract_document_manually()
sale_order = record.sale_order_ids[0]
sync_log = model.env['otl.appointment.sync.log']
model_id = model.env['ir.model'].search([('model', '=', 'sale.order')], limit=1)
sign_request = model.env['otl_document_sign.request'].sudo().search(
    [('model_id', '=', model_id.id), ('res_id', '=', sale_order.id)],
    order='create_date desc',
    limit=1)
if sign_request:

    if sign_request.state == 'signed':
        if not sign_request.completed_document:
            sign_request.generate_completed_document()
        contract_doc_attachment = sign_request.document_image()
        sale_order.write(
            {'contract_doc_attachment_id': contract_doc_attachment.id,
                'document_signed': True})
        result = sale_order.add_contract_document_file()
        if result.get('success', '') == 'true':
            sync_log.create({
                'appointment_id': record.id,
                'response': result,
                'name': 'Contract Document',
            })
        else:
            sync_log.create({
                'appointment_id': record.id,
                'response': result,
                'state': 'failed',
                'name': 'Contract Document',
            })
